-- gewonnen_monat setzen (alle betroffenen Monate + Firmen)
UPDATE deals_nk SET gewonnen_monat=monat, gewonnen_datum=datum WHERE monat IN ('2026-01','2026-02','2026-03','2026-04','2026-05') AND status='Gewonnen' AND company_id IN (1,3) AND (gewonnen_monat IS NULL OR gewonnen_monat='');
UPDATE deals_bk SET gewonnen_monat=monat, gewonnen_datum=datum WHERE monat IN ('2026-01','2026-02','2026-03','2026-04','2026-05') AND status='Gewonnen' AND company_id IN (1,3) AND (gewonnen_monat IS NULL OR gewonnen_monat='');
UPDATE deals_vl SET gewonnen_monat=monat, gewonnen_datum=datum WHERE monat IN ('2026-01','2026-02','2026-03','2026-04','2026-05') AND status='Gewonnen' AND company_id IN (1,3) AND (gewonnen_monat IS NULL OR gewonnen_monat='');

